package com.socialblog.notification.application;import com.fasterxml.jackson.databind.ObjectMapper;import com.socialblog.notification.domain.*;import com.socialblog.notification.repository.*;import org.junit.jupiter.api.Test;import java.util.*;import static org.mockito.Mockito.*;
class NotificationEventConsumerTest{@Test void createsFollowNotificationOnce()throws Exception{NotificationRepository notifications=mock(NotificationRepository.class);FollowProjectionRepository follows=mock(FollowProjectionRepository.class);ProcessedEventRepository processed=mock(ProcessedEventRepository.class);UUID event=UUID.randomUUID(),actor=UUID.randomUUID(),recipient=UUID.randomUUID();when(processed.existsById(event)).thenReturn(false,true);NotificationEventConsumer c=new NotificationEventConsumer(new ObjectMapper(),notifications,follows,processed);String raw="{\"eventId\":\""+event+"\",\"eventType\":\"UserFollowed\",\"actorId\":\""+actor+"\",\"payload\":{\"followerId\":\""+actor+"\",\"followedId\":\""+recipient+"\"}}";c.consume(raw);c.consume(raw);verify(follows,times(1)).save(any());verify(notifications,times(1)).save(argThat(n->n.getRecipientId().equals(recipient)&&n.getType()==Notification.Type.NEW_FOLLOWER));verify(processed,times(1)).save(any());}@Test void fansArticleOutToFollowersAndSkipsAuthor()throws Exception{NotificationRepository notifications=mock(NotificationRepository.class);FollowProjectionRepository follows=mock(FollowProjectionRepository.class);ProcessedEventRepository processed=mock(ProcessedEventRepository.class);UUID event=UUID.randomUUID(),author=UUID.randomUUID(),one=UUID.randomUUID(),two=UUID.randomUUID(),article=UUID.randomUUID();when(processed.existsById(event)).thenReturn(false);when(follows.findByIdFollowedId(author)).thenReturn(List.of(new FollowProjection(new FollowKey(one,author)),new FollowProjection(new FollowKey(two,author)),new FollowProjection(new FollowKey(author,author))));NotificationEventConsumer c=new NotificationEventConsumer(new ObjectMapper(),notifications,follows,processed);c.consume("{\"eventId\":\""+event+"\",\"eventType\":\"ArticlePublished\",\"actorId\":\""+author+"\",\"payload\":{\"articleId\":\""+article+"\"}}");verify(notifications,times(2)).save(argThat(n->n.getType()==Notification.Type.NEW_ARTICLE));verify(processed).save(any());}}
